solve(Nums) ->
    Max = lists:foldl(fun(_, Acc) -> Acc end, 0, lists:seq(1, 1 bsl length(Nums))),
    lists:foldl(
        fun(Mask, MaxSum) ->
            {A, B, C} = partition(Nums, Mask),
            Sum = xor_sum(A) + and_sum(B) + xor_sum(C),
            if Sum > MaxSum -> Sum; true -> MaxSum end
        end,
        -1,
        lists:seq(0, Max)
    ).

partition(Nums, Mask) ->
    lists:foldl(
        fun({Num, I}, {A, B, C}) ->
            case (Mask bsr I) band 2 of
                2 -> {A, [Num | B], C};
                1 -> {A, B, [Num | C]};
                0 -> {[Num | A], B, C}
            end
        end,
        {[], [], []},
        lists:zip(Nums, lists:seq(0, length(Nums) - 1))
    ).

xor_sum([]) -> 0;
xor_sum(List) -> lists:foldl(fun(X, Acc) -> X bxor Acc end, 0, List).

and_sum([]) -> 0;
and_sum([H | T]) -> lists:foldl(fun(X, Acc) -> X band Acc end, H, T).
